// Helper function: Get color for file status
static uint32_t get_status_color(FileStatus status) {
    switch (status) {
        case FileStatus::Modified:  return Theme::STATUS_MODIFIED;
        case FileStatus::Added:     return Theme::STATUS_ADDED;
        case FileStatus::Deleted:   return Theme::STATUS_DELETED;
        case FileStatus::Renamed:   return Theme::STATUS_RENAMED;
        case FileStatus::Untracked: return Theme::STATUS_ADDED;
        default:                    return Theme::TEXT_MUTED;
    }
}

// Helper function: Get total count of files that can be stashed (staged + changed)
size_t get_stashable_file_count() {
    return g_sidebar.staged_count + g_sidebar.changed_count;
}

// Helper function: Get file info at combined index (staged first, then changed)
SidebarFile* get_stashable_file(size_t index) {
    if (index < g_sidebar.staged_count) {
        return &g_sidebar.staged_files[index];
    }
    size_t changed_index = index - g_sidebar.staged_count;
    if (changed_index < g_sidebar.changed_count) {
        return &g_sidebar.changed_files[changed_index];
    }
    return nullptr;
}

