struct BranchDialogWidget : DialogWidget {
    // UI elements
    Label* name_label = nullptr;
    TextInput* name_input = nullptr;
    Label* error_label = nullptr;
    Label* source_label_title = nullptr;
    Label* source_label_value = nullptr;
    Checkbox* switch_checkbox = nullptr;
    FlexContainer* button_row = nullptr;
    Button* create_button = nullptr;
    Button* cancel_button = nullptr;

    // State
    char source_sha[Git::SHA1_HEX_SIZE + 1] = {};
    char source_display[128] = {};
    bool is_valid = false;

    // Static text buffers (widgets need persistent wchar_t* strings)
    wchar_t error_text[256] = {};
    wchar_t source_text[128] = {};

    // Static instance for callbacks
    static BranchDialogWidget* instance;

    void populate_content() override {
        // Convert source_display to wide string (source_sha and source_display are set by show())
        MultiByteToWideChar(CP_UTF8, 0, source_display, -1, source_text, 128);

        // Override content gap
        content->gap = BranchDialog::COMPACT_FIELD_SPACING;

        // Name label
        Label* lbl = g_widget_arena.create<Label>();
        lbl->text = L"Branch name";
        lbl->color = Theme::TEXT_SECONDARY;
        lbl->preferred_height = BranchDialog::LABEL_HEIGHT;
        widget_add_child(content, lbl);
        name_label = lbl;

        // Name input
        TextInput* input = g_widget_arena.create<TextInput>();
        input->placeholder = L"e.g., feature/new-feature";
        input->preferred_width = BranchDialog::WIDTH - DialogBase::PADDING * 2;
        input->preferred_height = BranchDialog::INPUT_HEIGHT;
        input->corner_radius = BranchDialog::INPUT_RADIUS;
        input->bg_color = BranchDialog::INPUT_BG;
        input->border_color = BranchDialog::INPUT_BORDER;
        input->border_focus = BranchDialog::INPUT_FOCUS;
        input->on_change = branch_dialog_widget_on_input_change;
        input->on_submit = branch_dialog_widget_on_input_submit;
        input->user_data = this;
        widget_add_child(content, input);
        name_input = input;

        // Error label (initially empty)
        Label* err = g_widget_arena.create<Label>();
        err->text = L"";
        err->color = BranchDialog::ERROR_TEXT;
        err->preferred_height = 18.0f;
        widget_add_child(content, err);
        error_label = err;

        // Source info label
        Label* src_title = g_widget_arena.create<Label>();
        src_title->text = L"Source";
        src_title->color = Theme::TEXT_SECONDARY;
        src_title->preferred_height = BranchDialog::LABEL_HEIGHT;
        widget_add_child(content, src_title);
        source_label_title = src_title;

        // Source value
        Label* src_val = g_widget_arena.create<Label>();
        src_val->text = source_text;
        src_val->color = Theme::TEXT_PRIMARY;
        src_val->preferred_height = 20.0f;
        widget_add_child(content, src_val);
        source_label_value = src_val;

        // Spacer
        Widget* spacer1 = g_widget_arena.create<Widget>();
        spacer1->preferred_height = 8.0f;
        widget_add_child(content, spacer1);

        // Switch checkbox
        Checkbox* chk = g_widget_arena.create<Checkbox>();
        chk->label = L"Switch to new branch";
        chk->checked = true;
        widget_add_child(content, chk);
        switch_checkbox = chk;

        // Spacer
        Widget* spacer2 = g_widget_arena.create<Widget>();
        spacer2->preferred_height = 8.0f;
        widget_add_child(content, spacer2);

        // Button row
        FlexContainer* row = g_widget_arena.create<FlexContainer>();
        row->direction = FlexDirection::Row;
        row->gap = BranchDialog::BUTTON_SPACING;
        row->justify = FlexJustify::End;
        row->preferred_height = BranchDialog::BUTTON_HEIGHT;
        button_row = row;

        // Create button (initially disabled)
        Button* create = g_widget_arena.create<Button>();
        create->text = L"Create";
        create->preferred_width = BranchDialog::BUTTON_WIDTH;
        create->preferred_height = BranchDialog::BUTTON_HEIGHT;
        create->width_mode = SizeMode::Fixed;
        create->height_mode = SizeMode::Fixed;
        create->corner_radius = BranchDialog::BUTTON_RADIUS;
        create->bg_normal = BranchDialog::BUTTON_PRIMARY_DISABLED;
        create->bg_hover = BranchDialog::BUTTON_PRIMARY_DISABLED;
        create->bg_pressed = BranchDialog::BUTTON_PRIMARY;
        create->flags &= ~WidgetFlags::Enabled;
        create->on_click = branch_dialog_widget_on_create_click;
        create->user_data = this;
        widget_add_child(row, create);
        create_button = create;

        // Cancel button
        Button* cancel = g_widget_arena.create<Button>();
        cancel->text = L"Cancel";
        cancel->preferred_width = BranchDialog::BUTTON_WIDTH;
        cancel->preferred_height = BranchDialog::BUTTON_HEIGHT;
        cancel->width_mode = SizeMode::Fixed;
        cancel->height_mode = SizeMode::Fixed;
        cancel->corner_radius = BranchDialog::BUTTON_RADIUS;
        cancel->bg_normal = BranchDialog::BUTTON_SECONDARY;
        cancel->bg_hover = BranchDialog::BUTTON_SECONDARY_HOVER;
        cancel->bg_pressed = Theme::BG_TERTIARY;
        cancel->on_click = branch_dialog_widget_on_cancel_click;
        cancel->user_data = this;
        widget_add_child(row, cancel);
        cancel_button = cancel;

        widget_add_child(content, row);
    }

    void set_initial_focus() override {
        g_event_dispatcher.set_focus(name_input);
    }

    void validate() {
        // Get branch name from input (convert from wide char)
        char branch_name[256] = {};
        WideCharToMultiByte(CP_UTF8, 0, name_input->text, -1, branch_name, sizeof(branch_name), nullptr, nullptr);

        // Empty name is invalid but no error message
        if (branch_name[0] == '\0') {
            is_valid = false;
            error_text[0] = L'\0';
            error_label->text = error_text;
            update_create_button_state();
            return;
        }

        // Check git name validity
        char error_utf8[256] = {};
        if (!git_is_valid_branch_name(branch_name, error_utf8, sizeof(error_utf8))) {
            is_valid = false;
            MultiByteToWideChar(CP_UTF8, 0, error_utf8, -1, error_text, 256);
            error_label->text = error_text;
            error_label->color = BranchDialog::ERROR_TEXT;
            update_create_button_state();
            return;
        }

        // Check if branch already exists
        if (git_branch_exists(&g_repo, branch_name)) {
            is_valid = false;
            swprintf_s(error_text, L"Branch '%hs' already exists", branch_name);
            error_label->text = error_text;
            error_label->color = BranchDialog::ERROR_TEXT;
            update_create_button_state();
            return;
        }

        // Valid
        is_valid = true;
        error_text[0] = L'\0';
        error_label->text = error_text;
        update_create_button_state();
    }

    void update_create_button_state() {
        if (is_valid) {
            create_button->flags |= WidgetFlags::Enabled;
            create_button->bg_normal = BranchDialog::BUTTON_PRIMARY;
            create_button->bg_hover = BranchDialog::BUTTON_PRIMARY_HOVER;
        } else {
            create_button->flags &= ~WidgetFlags::Enabled;
            create_button->bg_normal = BranchDialog::BUTTON_PRIMARY_DISABLED;
            create_button->bg_hover = BranchDialog::BUTTON_PRIMARY_DISABLED;
        }
        create_button->set_dirty();
    }

    void submit() {
        if (!is_valid) return;

        char branch_name[256] = {};
        WideCharToMultiByte(CP_UTF8, 0, name_input->text, -1, branch_name, sizeof(branch_name), nullptr, nullptr);

        char error[256] = {};
        bool success = git_branch_create(&g_repo, branch_name, source_sha, false, error, sizeof(error));

        if (success) {
            // Optionally checkout the new branch
            if (switch_checkbox->checked) {
                GitRef new_ref = {};
                new_ref.type = GitRef::Type::Local;
                strncpy_s(new_ref.name, branch_name, sizeof(new_ref.name) - 1);
                strncpy_s(new_ref.sha, source_sha, Git::SHA1_HEX_SIZE);

                CheckoutOptions opts = {};
                CheckoutResult result = {};
                git_branch_checkout(&g_repo, &new_ref, &opts, &result);

                // Update HEAD info
                git_read_head(&g_repo);
            }

            // Refresh sidebar
            sidebar_load_branches();
            sidebar_load_stashes();

            // Close dialog
            close();
        } else {
            // Show error in dialog
            MultiByteToWideChar(CP_UTF8, 0, error, -1, error_text, 256);
            error_label->text = error_text;
            error_label->color = BranchDialog::ERROR_TEXT;
            is_valid = false;
            update_create_button_state();
        }

        InvalidateRect(g_main_window, nullptr, FALSE);
    }
};

