// Show branch creation dialog
void branch_dialog_widget_show(const char* src_sha, const char* src_display) {
    dialog_arena_prepare();
    BranchDialogWidget::instance = g_widget_arena.create<BranchDialogWidget>();
    if (!BranchDialogWidget::instance) return;

    // Store source info in the instance
    strncpy_s(BranchDialogWidget::instance->source_sha, src_sha, Git::SHA1_HEX_SIZE);
    strncpy_s(BranchDialogWidget::instance->source_display, src_display, sizeof(BranchDialogWidget::instance->source_display) - 1);

    // Use base class show() with auto-height
    BranchDialogWidget::instance->show(L"Create New Branch", BranchDialog::WIDTH);
}

// Show branch dialog for creating branch from current HEAD
void show_branch_dialog() {
    RepoLockGuard lock;

    // Build source info from current HEAD
    char source_sha[Git::SHA1_HEX_SIZE + 1] = {};
    char source_display[128] = {};

    strncpy_s(source_sha, g_repo.head_sha, Git::SHA1_HEX_SIZE);

    if (g_repo.head_detached) {
        snprintf(source_display, sizeof(source_display), "HEAD (%.7s)", g_repo.head_sha);
    } else {
        snprintf(source_display, sizeof(source_display), "%s (%.7s)", g_repo.head_ref, g_repo.head_sha);
    }

    // Use widget-based dialog
    branch_dialog_widget_show(source_sha, source_display);
}

