// ============================================================================
// TagDialogWidget - Widget-based tag creation dialog
// ============================================================================

// Forward declarations for callbacks
static void tag_dialog_on_input_change(TextInput* input, void* user_data);
static void tag_dialog_on_input_submit(TextInput* input, void* user_data);
static void tag_dialog_on_annotated_change(Checkbox* chk, bool checked, void* user_data);
static void tag_dialog_on_create_click(Button* btn, void* user_data);
static void tag_dialog_on_cancel_click(Button* btn, void* user_data);

struct TagDialogWidget : DialogWidget {
    // UI elements
    Label* name_label = nullptr;
    TextInput* name_input = nullptr;
    Label* error_label = nullptr;
    Label* source_label_title = nullptr;
    Label* source_label_value = nullptr;
    Checkbox* annotated_checkbox = nullptr;
    Label* message_label = nullptr;
    TextInput* message_input = nullptr;
    FlexContainer* button_row = nullptr;
    Button* create_button = nullptr;
    Button* cancel_button = nullptr;

    // State
    char source_sha[Git::SHA1_HEX_SIZE + 1] = {};
    char source_display[128] = {};
    bool is_valid = false;

    // Static text buffers
    wchar_t error_text[256] = {};
    wchar_t source_text[128] = {};

    // Static instance for callbacks
    static TagDialogWidget* instance;

    void populate_content() override {
        // Convert source_display to wide string
        MultiByteToWideChar(CP_UTF8, 0, source_display, -1, source_text, 128);

        // Use tighter spacing for this compact dialog
        content->gap = BranchDialog::COMPACT_FIELD_SPACING;

        // Tag name label
        Label* lbl = g_widget_arena.create<Label>();
        lbl->text = L"Tag name";
        lbl->color = Theme::TEXT_SECONDARY;
        lbl->preferred_height = BranchDialog::LABEL_HEIGHT;
        widget_add_child(content, lbl);
        name_label = lbl;

        // Tag name input
        TextInput* input = g_widget_arena.create<TextInput>();
        input->placeholder = L"e.g., v1.0.0";
        input->preferred_width = BranchDialog::WIDTH - DialogBase::PADDING * 2;
        input->preferred_height = BranchDialog::INPUT_HEIGHT;
        input->corner_radius = BranchDialog::INPUT_RADIUS;
        input->bg_color = BranchDialog::INPUT_BG;
        input->border_color = BranchDialog::INPUT_BORDER;
        input->border_focus = BranchDialog::INPUT_FOCUS;
        input->on_change = tag_dialog_on_input_change;
        input->on_submit = tag_dialog_on_input_submit;
        input->user_data = this;
        widget_add_child(content, input);
        name_input = input;

        // Error label
        Label* err = g_widget_arena.create<Label>();
        err->text = L"";
        err->color = BranchDialog::ERROR_TEXT;
        err->preferred_height = 16.0f;
        widget_add_child(content, err);
        error_label = err;

        // Source label title
        Label* src_title = g_widget_arena.create<Label>();
        src_title->text = L"At commit";
        src_title->color = Theme::TEXT_SECONDARY;
        src_title->preferred_height = BranchDialog::LABEL_HEIGHT;
        widget_add_child(content, src_title);
        source_label_title = src_title;

        // Source label value
        Label* src_val = g_widget_arena.create<Label>();
        src_val->text = source_text;
        src_val->color = Theme::TEXT_MUTED;
        src_val->preferred_height = 20.0f;
        widget_add_child(content, src_val);
        source_label_value = src_val;

        // Spacer
        Widget* spacer = g_widget_arena.create<Widget>();
        spacer->preferred_height = 8.0f;
        widget_add_child(content, spacer);

        // Annotated checkbox
        Checkbox* chk = g_widget_arena.create<Checkbox>();
        chk->label = L"Create annotated tag (with message)";
        chk->checked = false;
        chk->on_change = tag_dialog_on_annotated_change;
        chk->user_data = this;
        widget_add_child(content, chk);
        annotated_checkbox = chk;

        // Message label (initially hidden)
        Label* msg_lbl = g_widget_arena.create<Label>();
        msg_lbl->text = L"Message";
        msg_lbl->color = Theme::TEXT_SECONDARY;
        msg_lbl->preferred_height = BranchDialog::LABEL_HEIGHT;
        msg_lbl->flags &= ~WidgetFlags::Visible;
        widget_add_child(content, msg_lbl);
        message_label = msg_lbl;

        // Message input (initially hidden)
        TextInput* msg_input = g_widget_arena.create<TextInput>();
        msg_input->placeholder = L"Tag message (optional)";
        msg_input->preferred_width = BranchDialog::WIDTH - DialogBase::PADDING * 2;
        msg_input->preferred_height = BranchDialog::INPUT_HEIGHT;
        msg_input->corner_radius = BranchDialog::INPUT_RADIUS;
        msg_input->bg_color = BranchDialog::INPUT_BG;
        msg_input->border_color = BranchDialog::INPUT_BORDER;
        msg_input->border_focus = BranchDialog::INPUT_FOCUS;
        msg_input->user_data = this;
        msg_input->flags &= ~WidgetFlags::Visible;
        widget_add_child(content, msg_input);
        message_input = msg_input;

        // Spacer
        Widget* spacer2 = g_widget_arena.create<Widget>();
        spacer2->preferred_height = 8.0f;
        widget_add_child(content, spacer2);

        // Button row
        FlexContainer* row = g_widget_arena.create<FlexContainer>();
        row->direction = FlexDirection::Row;
        row->gap = BranchDialog::BUTTON_SPACING;
        row->justify = FlexJustify::End;
        row->preferred_height = BranchDialog::BUTTON_HEIGHT;
        button_row = row;

        // Create button (initially disabled)
        Button* create = g_widget_arena.create<Button>();
        create->text = L"Create Tag";
        create->preferred_width = BranchDialog::BUTTON_WIDTH + 20.0f;
        create->preferred_height = BranchDialog::BUTTON_HEIGHT;
        create->width_mode = SizeMode::Fixed;
        create->height_mode = SizeMode::Fixed;
        create->corner_radius = BranchDialog::BUTTON_RADIUS;
        create->bg_normal = BranchDialog::BUTTON_PRIMARY_DISABLED;
        create->bg_hover = BranchDialog::BUTTON_PRIMARY_DISABLED;
        create->bg_pressed = BranchDialog::BUTTON_PRIMARY;
        create->flags &= ~WidgetFlags::Enabled;
        create->on_click = tag_dialog_on_create_click;
        create->user_data = this;
        widget_add_child(row, create);
        create_button = create;

        // Cancel button
        Button* cancel = g_widget_arena.create<Button>();
        cancel->text = L"Cancel";
        cancel->preferred_width = BranchDialog::BUTTON_WIDTH;
        cancel->preferred_height = BranchDialog::BUTTON_HEIGHT;
        cancel->width_mode = SizeMode::Fixed;
        cancel->height_mode = SizeMode::Fixed;
        cancel->corner_radius = BranchDialog::BUTTON_RADIUS;
        cancel->bg_normal = BranchDialog::BUTTON_SECONDARY;
        cancel->bg_hover = BranchDialog::BUTTON_SECONDARY_HOVER;
        cancel->bg_pressed = Theme::BG_TERTIARY;
        cancel->on_click = tag_dialog_on_cancel_click;
        cancel->user_data = this;
        widget_add_child(row, cancel);
        cancel_button = cancel;

        widget_add_child(content, row);
    }

    void set_initial_focus() override {
        g_event_dispatcher.set_focus(name_input);
    }

    void toggle_message_visibility() {
        bool show = annotated_checkbox->checked;
        if (show) {
            message_label->flags |= WidgetFlags::Visible;
            message_input->flags |= WidgetFlags::Visible;
        } else {
            message_label->flags &= ~WidgetFlags::Visible;
            message_input->flags &= ~WidgetFlags::Visible;
        }
        // Re-measure and layout the dialog (auto-height will recalculate)
        measure_and_layout();
        InvalidateRect(g_main_window, nullptr, FALSE);
    }

    void validate() {
        // Get tag name from input
        char tag_name[256] = {};
        WideCharToMultiByte(CP_UTF8, 0, name_input->text, -1, tag_name, sizeof(tag_name), nullptr, nullptr);

        // Empty name is invalid but no error message
        if (tag_name[0] == '\0') {
            is_valid = false;
            error_text[0] = L'\0';
            error_label->text = error_text;
            update_create_button_state();
            return;
        }

        // Check if tag already exists
        if (git_tag_exists(&g_repo, tag_name)) {
            is_valid = false;
            swprintf_s(error_text, L"Tag '%hs' already exists", tag_name);
            error_label->text = error_text;
            error_label->color = BranchDialog::ERROR_TEXT;
            update_create_button_state();
            return;
        }

        // Check for invalid characters (tags follow similar rules to branches)
        // Simple check: no spaces, no control chars, no special git chars
        for (const char* p = tag_name; *p; ++p) {
            if (*p == ' ' || *p == '~' || *p == '^' || *p == ':' || *p == '?' ||
                *p == '*' || *p == '[' || *p == '\\' || static_cast<unsigned char>(*p) < 32) {
                is_valid = false;
                wcscpy_s(error_text, L"Invalid tag name (contains forbidden characters)");
                error_label->text = error_text;
                error_label->color = BranchDialog::ERROR_TEXT;
                update_create_button_state();
                return;
            }
        }

        // Valid
        is_valid = true;
        error_text[0] = L'\0';
        error_label->text = error_text;
        update_create_button_state();
    }

    void update_create_button_state() {
        if (is_valid) {
            create_button->flags |= WidgetFlags::Enabled;
            create_button->bg_normal = BranchDialog::BUTTON_PRIMARY;
            create_button->bg_hover = BranchDialog::BUTTON_PRIMARY_HOVER;
        } else {
            create_button->flags &= ~WidgetFlags::Enabled;
            create_button->bg_normal = BranchDialog::BUTTON_PRIMARY_DISABLED;
            create_button->bg_hover = BranchDialog::BUTTON_PRIMARY_DISABLED;
        }
        create_button->set_dirty();
    }

    void submit() {
        if (!is_valid) return;

        char tag_name[256] = {};
        WideCharToMultiByte(CP_UTF8, 0, name_input->text, -1, tag_name, sizeof(tag_name), nullptr, nullptr);

        // Get message if annotated
        char message[512] = {};
        const char* msg_ptr = nullptr;
        if (annotated_checkbox->checked && message_input->text[0] != L'\0') {
            WideCharToMultiByte(CP_UTF8, 0, message_input->text, -1, message, sizeof(message), nullptr, nullptr);
            msg_ptr = message;
        }

        char error[256] = {};
        bool success = git_tag_create(&g_repo, tag_name, source_sha, msg_ptr, error, sizeof(error));

        if (success) {
            // Refresh sidebar to show new tag
            sidebar_load_branches();

            // Close dialog
            close();
        } else {
            // Show error in dialog
            MultiByteToWideChar(CP_UTF8, 0, error, -1, error_text, 256);
            error_label->text = error_text;
            error_label->color = BranchDialog::ERROR_TEXT;
            is_valid = false;
            update_create_button_state();
        }

        InvalidateRect(g_main_window, nullptr, FALSE);
    }
};

// Static instance
static TagDialogWidget s_tag_dialog_instance;
TagDialogWidget* TagDialogWidget::instance = nullptr;

// Callback functions for TagDialogWidget
static void tag_dialog_on_input_change(TextInput* input, void* user_data) {
    (void)input;
    TagDialogWidget* dlg = static_cast<TagDialogWidget*>(user_data);
    if (dlg) {
        dlg->validate();
        InvalidateRect(g_main_window, nullptr, FALSE);
    }
}

static void tag_dialog_on_input_submit(TextInput* input, void* user_data) {
    (void)input;
    TagDialogWidget* dlg = static_cast<TagDialogWidget*>(user_data);
    if (dlg && dlg->is_valid) {
        dlg->submit();
    }
}

static void tag_dialog_on_annotated_change(Checkbox* chk, bool checked, void* user_data) {
    (void)chk;
    (void)checked;
    TagDialogWidget* dlg = static_cast<TagDialogWidget*>(user_data);
    if (dlg) {
        dlg->toggle_message_visibility();
    }
}

static void tag_dialog_on_create_click(Button* btn, void* user_data) {
    (void)btn;
    TagDialogWidget* dlg = static_cast<TagDialogWidget*>(user_data);
    if (dlg && dlg->is_valid) {
        dlg->submit();
    }
}

static void tag_dialog_on_cancel_click(Button* btn, void* user_data) {
    (void)btn;
    TagDialogWidget* dlg = static_cast<TagDialogWidget*>(user_data);
    if (dlg) {
        dlg->close();
    }
}

