// Forward declarations for callbacks
static void auth_dialog_widget_on_username_submit(TextInput* input, void* user_data);
static void auth_dialog_widget_on_password_submit(TextInput* input, void* user_data);
static void auth_dialog_widget_on_login_click(Button* btn, void* user_data);
static void auth_dialog_widget_on_cancel_click(Button* btn, void* user_data);

struct AuthDialogWidget : DialogWidget {
    // UI elements
    Label* title_label = nullptr;
    Label* username_label = nullptr;
    TextInput* username_input = nullptr;
    Label* password_label = nullptr;
    TextInput* password_input = nullptr;
    Label* error_label = nullptr;
    FlexContainer* button_row = nullptr;
    Button* login_button = nullptr;
    Button* cancel_button = nullptr;

    // State
    char host[256] = {};

    // Static text buffers (widgets need persistent wchar_t* strings)
    wchar_t title_text[300] = {};
    wchar_t error_text[256] = {};

    // Static instance for callbacks
    static AuthDialogWidget* instance;

    void populate_content() override {
        // Spacer at top
        Widget* top_spacer = g_widget_arena.create<Widget>();
        top_spacer->preferred_height = 8.0f;
        widget_add_child(content, top_spacer);

        // Username label
        Label* user_lbl = g_widget_arena.create<Label>();
        user_lbl->text = L"Username";
        user_lbl->color = Theme::TEXT_SECONDARY;
        user_lbl->preferred_height = AuthDialog::LABEL_HEIGHT;
        widget_add_child(content, user_lbl);
        username_label = user_lbl;

        // Username input
        TextInput* user_input = g_widget_arena.create<TextInput>();
        user_input->placeholder = L"Enter username";
        user_input->preferred_width = AuthDialog::WIDTH - AuthDialog::PADDING * 2;
        user_input->preferred_height = AuthDialog::INPUT_HEIGHT;
        user_input->corner_radius = 4.0f;
        user_input->bg_color = AuthDialog::INPUT_BG;
        user_input->border_color = AuthDialog::INPUT_BORDER;
        user_input->border_focus = AuthDialog::INPUT_FOCUS;
        user_input->on_submit = auth_dialog_widget_on_username_submit;
        user_input->user_data = this;
        widget_add_child(content, user_input);
        username_input = user_input;

        // Spacer
        Widget* spacer = g_widget_arena.create<Widget>();
        spacer->preferred_height = AuthDialog::FIELD_SPACING - 4.0f;
        widget_add_child(content, spacer);

        // Password label
        Label* pwd_lbl = g_widget_arena.create<Label>();
        pwd_lbl->text = L"Password";
        pwd_lbl->color = Theme::TEXT_SECONDARY;
        pwd_lbl->preferred_height = AuthDialog::LABEL_HEIGHT;
        widget_add_child(content, pwd_lbl);
        password_label = pwd_lbl;

        // Password input
        TextInput* pwd_input = g_widget_arena.create<TextInput>();
        pwd_input->placeholder = L"Enter password";
        pwd_input->preferred_width = AuthDialog::WIDTH - AuthDialog::PADDING * 2;
        pwd_input->preferred_height = AuthDialog::INPUT_HEIGHT;
        pwd_input->corner_radius = 4.0f;
        pwd_input->bg_color = AuthDialog::INPUT_BG;
        pwd_input->border_color = AuthDialog::INPUT_BORDER;
        pwd_input->border_focus = AuthDialog::INPUT_FOCUS;
        pwd_input->password_mode = true;
        pwd_input->on_submit = auth_dialog_widget_on_password_submit;
        pwd_input->user_data = this;
        widget_add_child(content, pwd_input);
        password_input = pwd_input;

        // Error label (initially empty)
        Label* err = g_widget_arena.create<Label>();
        err->text = L"";
        err->color = AuthDialog::ERROR_TEXT;
        err->preferred_height = 18.0f;
        widget_add_child(content, err);
        error_label = err;

        // Button row
        FlexContainer* row = g_widget_arena.create<FlexContainer>();
        row->direction = FlexDirection::Row;
        row->gap = AuthDialog::BUTTON_SPACING;
        row->justify = FlexJustify::End;
        row->preferred_height = AuthDialog::BUTTON_HEIGHT;
        button_row = row;

        // Login button
        Button* login = g_widget_arena.create<Button>();
        login->text = L"Login";
        login->preferred_width = AuthDialog::BUTTON_WIDTH;
        login->preferred_height = AuthDialog::BUTTON_HEIGHT;
        login->width_mode = SizeMode::Fixed;
        login->height_mode = SizeMode::Fixed;
        login->corner_radius = 4.0f;
        login->bg_normal = AuthDialog::BUTTON_NORMAL;
        login->bg_hover = AuthDialog::BUTTON_HOVER;
        login->bg_pressed = AuthDialog::BUTTON_ACTIVE;
        login->on_click = auth_dialog_widget_on_login_click;
        login->user_data = this;
        widget_add_child(row, login);
        login_button = login;

        // Cancel button
        Button* cancel = g_widget_arena.create<Button>();
        cancel->text = L"Cancel";
        cancel->preferred_width = AuthDialog::BUTTON_WIDTH;
        cancel->preferred_height = AuthDialog::BUTTON_HEIGHT;
        cancel->width_mode = SizeMode::Fixed;
        cancel->height_mode = SizeMode::Fixed;
        cancel->corner_radius = 4.0f;
        cancel->bg_normal = AuthDialog::BUTTON_CANCEL;
        cancel->bg_hover = AuthDialog::BUTTON_CANCEL_HOVER;
        cancel->bg_pressed = Theme::BG_TERTIARY;
        cancel->on_click = auth_dialog_widget_on_cancel_click;
        cancel->user_data = this;
        widget_add_child(row, cancel);
        cancel_button = cancel;

        widget_add_child(content, row);
    }

    void set_initial_focus() override {
        g_event_dispatcher.set_focus(username_input);
    }

    void submit() {
        // Convert username and password to UTF-8
        char username_utf8[128] = {};
        char password_utf8[512] = {};
        WideCharToMultiByte(CP_UTF8, 0, username_input->text, -1, username_utf8, sizeof(username_utf8), nullptr, nullptr);
        WideCharToMultiByte(CP_UTF8, 0, password_input->text, -1, password_utf8, sizeof(password_utf8), nullptr, nullptr);

        // Validate inputs
        if (username_utf8[0] == '\0' || password_utf8[0] == '\0') {
            wcscpy_s(error_text, L"Username and password required");
            error_label->text = error_text;
            error_label->set_dirty();
            InvalidateRect(g_main_window, nullptr, FALSE);
            return;
        }

        // Store credentials in Windows Credential Manager - remove old first for clean state
        LOG("Auth dialog - Storing credentials (username: %s)", username_utf8);
        wchar_t target[512];
        CredentialStore::build_target(host, target, _countof(target));
        CredentialStore::remove(target);  // Clear any stale/invalid credentials
        CredentialStore::store(target, username_utf8, password_utf8);

        // Close dialog and signal success to retry the pending operation
        close();
        PostMessage(g_main_window, WM_AUTH_COMPLETE, 1, 0);
    }
};

// Static instance
AuthDialogWidget* AuthDialogWidget::instance = nullptr;

