// Create and show the auth dialog widget
void auth_dialog_widget_show(const char* host) {
    if (!host) return;

    dialog_arena_prepare();
    AuthDialogWidget::instance = g_widget_arena.create<AuthDialogWidget>();
    if (!AuthDialogWidget::instance) return;

    // Store host in the instance
    strncpy_s(AuthDialogWidget::instance->host, host, sizeof(AuthDialogWidget::instance->host) - 1);

    // Create title text before calling show()
    wchar_t host_wide[256];
    MultiByteToWideChar(CP_UTF8, 0, host, -1, host_wide, 256);
    swprintf_s(AuthDialogWidget::instance->title_text, L"Sign in to %s", host_wide);

    // Use base class show() with auto-height
    AuthDialogWidget::instance->show(AuthDialogWidget::instance->title_text, AuthDialog::WIDTH);
}

