// Forward declarations for callbacks
static void oauth_dialog_widget_on_copy_click(Button* btn, void* user_data);
static void oauth_dialog_widget_on_browser_click(Button* btn, void* user_data);
static void oauth_dialog_widget_on_cancel_click(Button* btn, void* user_data);

struct OAuthDialogWidget : DialogWidget {
    // UI elements
    Label* instructions_label = nullptr;
    Label* code_label = nullptr;
    FlexContainer* action_button_row = nullptr;
    Button* copy_button = nullptr;
    Button* browser_button = nullptr;
    Label* status_label = nullptr;
    Button* cancel_button = nullptr;

    // State
    char host[256] = {};
    char user_code[16] = {};
    char verification_url[128] = {};
    int seconds_remaining = 0;
    int poll_interval = 5;
    OAuthDeviceFlow flow = {};

    // Background polling thread
    HANDLE poll_thread = nullptr;
    volatile bool cancel_requested = false;
    volatile bool poll_complete = false;
    volatile bool poll_success = false;

    // Static text buffers (widgets need persistent wchar_t* strings)
    wchar_t code_text[32] = {};
    wchar_t status_text[256] = {};

    // Static instance for callbacks and thread
    static OAuthDialogWidget* instance;

    void populate_content() override {
        // Convert user code to wide string
        MultiByteToWideChar(CP_UTF8, 0, user_code, -1, code_text, 32);

        // Initial status
        wcscpy_s(status_text, L"Waiting for authorization...");

        // Override content alignment
        content->align = FlexAlign::Center;
        content->gap = OAuthDialog::FIELD_SPACING;

        // Instructions label
        Label* instr = g_widget_arena.create<Label>();
        instr->text = L"Enter this code at github.com/login/device:";
        instr->color = Theme::TEXT_SECONDARY;
        instr->preferred_height = 24.0f;
        instr->text_align = DWRITE_TEXT_ALIGNMENT_CENTER;
        widget_add_child(content, instr);
        instructions_label = instr;

        // Code display
        Label* code = g_widget_arena.create<Label>();
        code->text = code_text;
        code->text_format = g_text_format_oauth_code;
        code->color = OAuthDialog::CODE_TEXT;
        code->preferred_width = OAuthDialog::CODE_BOX_WIDTH;
        code->preferred_height = OAuthDialog::CODE_BOX_HEIGHT;
        code->padding_left = 16.0f;
        code->padding_right = 16.0f;
        code->padding_top = 12.0f;
        code->padding_bottom = 12.0f;
        code->text_align = DWRITE_TEXT_ALIGNMENT_CENTER;
        code->para_align = DWRITE_PARAGRAPH_ALIGNMENT_CENTER;
        widget_add_child(content, code);
        code_label = code;

        // Spacer
        Widget* spacer = g_widget_arena.create<Widget>();
        spacer->preferred_height = 8.0f;
        widget_add_child(content, spacer);

        // Action button row
        FlexContainer* row = g_widget_arena.create<FlexContainer>();
        row->direction = FlexDirection::Row;
        row->gap = OAuthDialog::BUTTON_SPACING;
        row->justify = FlexJustify::Center;
        row->preferred_height = OAuthDialog::BUTTON_HEIGHT + 8.0f;
        action_button_row = row;

        // Copy Code button
        Button* copy = g_widget_arena.create<Button>();
        copy->text = L"Copy Code";
        copy->preferred_width = OAuthDialog::BUTTON_WIDTH;
        copy->preferred_height = OAuthDialog::BUTTON_HEIGHT;
        copy->width_mode = SizeMode::Fixed;
        copy->height_mode = SizeMode::Fixed;
        copy->corner_radius = 4.0f;
        copy->bg_normal = OAuthDialog::BUTTON_SECONDARY;
        copy->bg_hover = OAuthDialog::BUTTON_SECONDARY_HOVER;
        copy->bg_pressed = Theme::BG_TERTIARY;
        copy->on_click = oauth_dialog_widget_on_copy_click;
        copy->user_data = this;
        widget_add_child(row, copy);
        copy_button = copy;

        // Open Browser button
        Button* browser = g_widget_arena.create<Button>();
        browser->text = L"Open Browser";
        browser->preferred_width = OAuthDialog::BUTTON_WIDTH;
        browser->preferred_height = OAuthDialog::BUTTON_HEIGHT;
        browser->width_mode = SizeMode::Fixed;
        browser->height_mode = SizeMode::Fixed;
        browser->corner_radius = 4.0f;
        browser->bg_normal = OAuthDialog::BUTTON_PRIMARY;
        browser->bg_hover = OAuthDialog::BUTTON_PRIMARY_HOVER;
        browser->bg_pressed = Theme::ACCENT_PRESSED;
        browser->text_color = 0xFFFFFFFF;
        browser->on_click = oauth_dialog_widget_on_browser_click;
        browser->user_data = this;
        widget_add_child(row, browser);
        browser_button = browser;

        widget_add_child(content, row);

        // Status label
        Label* status = g_widget_arena.create<Label>();
        status->text = status_text;
        status->color = OAuthDialog::STATUS_TEXT;
        status->preferred_height = 24.0f;
        status->text_align = DWRITE_TEXT_ALIGNMENT_CENTER;
        widget_add_child(content, status);
        status_label = status;

        // Cancel button row
        FlexContainer* cancel_row = g_widget_arena.create<FlexContainer>();
        cancel_row->direction = FlexDirection::Row;
        cancel_row->justify = FlexJustify::End;
        cancel_row->preferred_height = OAuthDialog::BUTTON_HEIGHT;

        Button* cancel = g_widget_arena.create<Button>();
        cancel->text = L"Cancel";
        cancel->preferred_width = OAuthDialog::BUTTON_WIDTH;
        cancel->preferred_height = OAuthDialog::BUTTON_HEIGHT;
        cancel->width_mode = SizeMode::Fixed;
        cancel->height_mode = SizeMode::Fixed;
        cancel->corner_radius = 4.0f;
        cancel->bg_normal = OAuthDialog::BUTTON_SECONDARY;
        cancel->bg_hover = OAuthDialog::BUTTON_SECONDARY_HOVER;
        cancel->bg_pressed = Theme::BG_TERTIARY;
        cancel->on_click = oauth_dialog_widget_on_cancel_click;
        cancel->user_data = this;
        widget_add_child(cancel_row, cancel);
        cancel_button = cancel;

        widget_add_child(content, cancel_row);
    }

    void set_initial_focus() override {
        g_event_dispatcher.set_focus(copy_button);
    }

    void update_status() {
        if (poll_complete && poll_success) {
            wcscpy_s(status_text, L"Authorization successful!");
        } else if (poll_complete && !poll_success) {
            // Error already set in status_text by poll thread
        } else {
            int minutes = seconds_remaining / 60;
            int seconds = seconds_remaining % 60;
            swprintf_s(status_text, L"Waiting for authorization... (%d:%02d)", minutes, seconds);
        }
        if (status_label) {
            status_label->text = status_text;
            status_label->set_dirty();
        }
    }

    void copy_code() {
        if (copy_to_clipboard(user_code)) {
            wcscpy_s(status_text, L"Code copied to clipboard!");
            if (status_label) {
                status_label->text = status_text;
                status_label->color = OAuthDialog::SUCCESS_TEXT;
                status_label->set_dirty();
            }
            InvalidateRect(g_main_window, nullptr, FALSE);
        }
    }

    void open_browser() {
        open_url_in_browser(verification_url);
    }

    void close() override {
        // Signal cancel to polling thread
        cancel_requested = true;

        // Kill countdown timer
        KillTimer(g_main_window, OAUTH_COUNTDOWN_TIMER_ID);

        // Wait for poll thread to finish (non-blocking with timeout)
        if (poll_thread) {
            WaitForSingleObject(poll_thread, 2000);
            CloseHandle(poll_thread);
            poll_thread = nullptr;
        }

        // Call base class close
        DialogWidget::close();
    }

    void on_close() override {
        // Signal cancel to polling thread
        cancel_requested = true;
        KillTimer(g_main_window, OAUTH_COUNTDOWN_TIMER_ID);
    }
};

// Static instance
OAuthDialogWidget* OAuthDialogWidget::instance = nullptr;

// Callback functions for OAuthDialogWidget
