// Code Editor test dialog
struct CodeEditorTestDialogWidget : DialogWidget {
    CodeEditor::CodeEditorWidget* editor = nullptr;
    CodeEditor::TextDocument* test_doc = nullptr;

    static CodeEditorTestDialogWidget* instance;

    ~CodeEditorTestDialogWidget() {
        if (test_doc) {
            delete test_doc;
            test_doc = nullptr;
        }
    }

    void populate_content() override {
        content->gap = 0.0f;
        content->padding_left = 0.0f;
        content->padding_right = 0.0f;
        content->padding_top = 0.0f;
        content->padding_bottom = 0.0f;

        // Create code editor widget
        editor = g_widget_arena.create<CodeEditor::CodeEditorWidget>();
        editor->width_mode = SizeMode::Fill;
        editor->height_mode = SizeMode::Fill;
        editor->flex = 1.0f;  // Take remaining space
        widget_add_child(content, editor);

        // Create test document with sample content
        static const char* test_content =
            "// CodeEditorWidget Test File\n"
            "// Phase 3: Basic Rendering\n"
            "\n"
            "#include <iostream>\n"
            "#include <vector>\n"
            "#include <string>\n"
            "\n"
            "namespace CodeEditor {\n"
            "\n"
            "class TestClass {\n"
            "public:\n"
            "    TestClass() = default;\n"
            "    ~TestClass() = default;\n"
            "\n"
            "    void print_message() {\n"
            "        std::cout << \"Hello from CodeEditorWidget!\" << std::endl;\n"
            "    }\n"
            "\n"
            "    int calculate(int a, int b) {\n"
            "        return a + b;\n"
            "    }\n"
            "};\n"
            "\n"
            "} // namespace CodeEditor\n"
            "\n"
            "int main() {\n"
            "    CodeEditor::TestClass test;\n"
            "    test.print_message();\n"
            "\n"
            "    int result = test.calculate(40, 2);\n"
            "    std::cout << \"Result: \" << result << std::endl;\n"
            "\n"
            "    // Test scrolling with more lines\n"
            "    for (int i = 0; i < 50; i++) {\n"
            "        std::cout << \"Line \" << i << std::endl;\n"
            "    }\n"
            "\n"
            "    return 0;\n"
            "}\n";

        test_doc = CodeEditor::TextDocument::from_string(test_content);
        if (test_doc && editor) {
            // Set a fake path with .cpp extension to enable C++ syntax highlighting
            test_doc->set_source_path("test.cpp");
            editor->set_document(test_doc);
        }
    }

    void set_initial_focus() override {
        // Editor will handle focus
    }
};

CodeEditorTestDialogWidget* CodeEditorTestDialogWidget::instance = nullptr;

static void debug_test_on_code_editor_click(Button* btn, void* user_data) {
    (void)btn;
    DebugTestDialogWidget* dlg = static_cast<DebugTestDialogWidget*>(user_data);
    if (dlg) dlg->close();

    dialog_arena_prepare();
    CodeEditorTestDialogWidget::instance = g_widget_arena.create<CodeEditorTestDialogWidget>();
    if (!CodeEditorTestDialogWidget::instance) return;

    CodeEditorTestDialogWidget::instance->show(L"Code Editor Test", 600.0f, 500.0f);
}

static void debug_test_dialog_show() {
    dialog_arena_prepare();
    DebugTestDialogWidget::instance = g_widget_arena.create<DebugTestDialogWidget>();
    if (!DebugTestDialogWidget::instance) return;

    DebugTestDialogWidget::instance->show(L"Debug Tools", 200.0f);
}

#endif // GITSMARTER_DEBUG

// ============================================================================
// Public Dialog API
// ============================================================================

// Render all active dialog widgets (called from platform.cpp render_frame)
void dialog_widgets_render() {
    // Render dialogs in priority order (topmost last) using base class render()
    // Branch dialog is lowest priority
    if (BranchDialogWidget::instance) {
        BranchDialogWidget::instance->render();
    }
    // Branch rename dialog
    if (BranchRenameDialogWidget::instance) {
        BranchRenameDialogWidget::instance->render();
    }
    // Tag dialog
    if (TagDialogWidget::instance) {
        TagDialogWidget::instance->render();
    }
    // Auth dialog
    if (AuthDialogWidget::instance) {
        AuthDialogWidget::instance->render();
    }
    // OAuth dialog
    if (OAuthDialogWidget::instance) {
        OAuthDialogWidget::instance->render();
    }
    // Stash dialog is highest priority
    if (StashDialogWidget::instance) {
        StashDialogWidget::instance->render();
    }
    // Clone dialog (topmost when active)
    if (CloneDialogWidget::instance) {
        CloneDialogWidget::instance->render();
    }
#ifdef GITSMARTER_DEBUG
    // Debug test dialog (topmost in debug builds)
    if (DebugTestDialogWidget::instance) {
        DebugTestDialogWidget::instance->render();
    }
    // Code editor test dialog
    if (CodeEditorTestDialogWidget::instance) {
        CodeEditorTestDialogWidget::instance->render();
    }
#endif
}

// Check if any dialog is currently active
bool any_dialog_widget_is_active() {
    bool active = (BranchDialogWidget::instance && BranchDialogWidget::instance->is_active()) ||
                  (BranchRenameDialogWidget::instance && BranchRenameDialogWidget::instance->is_active()) ||
                  (TagDialogWidget::instance && TagDialogWidget::instance->is_active()) ||
                  (AuthDialogWidget::instance && AuthDialogWidget::instance->is_active()) ||
                  (OAuthDialogWidget::instance && OAuthDialogWidget::instance->is_active()) ||
                  (StashDialogWidget::instance && StashDialogWidget::instance->is_active()) ||
                  (CloneDialogWidget::instance && CloneDialogWidget::instance->is_active());
#ifdef GITSMARTER_DEBUG
    active = active || (DebugTestDialogWidget::instance && DebugTestDialogWidget::instance->is_active());
    active = active || (CodeEditorTestDialogWidget::instance && CodeEditorTestDialogWidget::instance->is_active());
#endif
    return active;
}

// NOTE: show_auth_dialog is defined in platform.cpp (calls auth_dialog_widget_show)

// Handle OAuth countdown timer (called from platform.cpp WM_TIMER handler)
void oauth_dialog_handle_timer() {
    if (OAuthDialogWidget::instance && OAuthDialogWidget::instance->is_active()) {
        OAuthDialogWidget* oauth = OAuthDialogWidget::instance;
        if (oauth->seconds_remaining > 0) {
            oauth->seconds_remaining--;
        }
    }
}

// Close all active dialogs (called from platform.cpp WM_CLOSE handler)
void dialog_widgets_close_all() {
    if (CloneDialogWidget::instance && CloneDialogWidget::instance->is_active()) {
        CloneDialogWidget::instance->close();
    }
    if (StashDialogWidget::instance && StashDialogWidget::instance->is_active()) {
        StashDialogWidget::instance->close();
    }
    if (OAuthDialogWidget::instance && OAuthDialogWidget::instance->is_active()) {
        OAuthDialogWidget::instance->close();
    }
    if (AuthDialogWidget::instance && AuthDialogWidget::instance->is_active()) {
        AuthDialogWidget::instance->close();
    }
    if (TagDialogWidget::instance && TagDialogWidget::instance->is_active()) {
        TagDialogWidget::instance->close();
    }
    if (BranchRenameDialogWidget::instance && BranchRenameDialogWidget::instance->is_active()) {
        BranchRenameDialogWidget::instance->close();
    }
    if (BranchDialogWidget::instance && BranchDialogWidget::instance->is_active()) {
        BranchDialogWidget::instance->close();
    }
}

// Animation tick for dialogs (called from platform.cpp animation timer)
void dialog_widgets_tick(float dt) {
    // Dialog trees use the same animation tick as other widgets
    (void)dt;  // Currently unused
}

